// Check which classes breached the attendance drop threshold
// Threshold: attendance dropped >30% vs 4-week avg for 2+ consecutive sessions
const classes = $input.first().json.class_sessions;

const breached = classes.filter(c => {
  const dropPct = (c.four_week_avg - c.attendees) / c.four_week_avg;
  return dropPct > 0.30 && c.consecutive_low_sessions >= 2;
});

if (breached.length === 0) {
  return [{ json: { trigger_fired: false, reason: 'No class attendance drop threshold breached today.' } }];
}

// Collect unique attendee IDs from all breached classes
const uniqueIds = [...new Set(breached.flatMap(c => c.attendee_ids))];
const classNames = breached.map(c => c.class_name).join(', ');

return [{ json: { trigger_fired: true, trigger_type: 'class_drop', affected_class_names: classNames, candidate_member_ids: uniqueIds } }];

// Check if studio-wide check-ins dropped >20% vs 7-day average
const data = $input.first().json;
const dropPct = (data.seven_day_avg - data.today_checkins) / data.seven_day_avg;

if (dropPct <= 0.20) {
  return [{ json: { trigger_fired: false, reason: `Check-in drop ${Math.round(dropPct * 100)}% — below 20% threshold.` } }];
}

return [{ json: {
  trigger_fired: true,
  trigger_type: 'studio_drop',
  drop_pct: Math.round(dropPct * 100),
  candidate_member_ids: data.active_member_ids
} }];

// Filter to members who have NOT received a survey in the past 5 weeks (35 days)
const triggerData = $('IF: Class Threshold Breached?').first().json;
const logData = $('Load Survey Sent Log (Class)').first().json;

const COOLDOWN_DAYS = 35;
const today = new Date();

const sentMap = {};
(logData.survey_sent_log || []).forEach(r => { sentMap[r.member_id] = new Date(r.last_survey_sent); });

const eligible = (triggerData.candidate_member_ids || []).filter(id => {
  const lastSent = sentMap[id];
  if (!lastSent) return true; // never surveyed
  const daysSince = (today - lastSent) / (1000 * 60 * 60 * 24);
  return daysSince >= COOLDOWN_DAYS;
});

if (eligible.length === 0) {
  return [{ json: { send_surveys: false, reason: 'All candidates in cooldown window.' } }];
}

return eligible.map(id => ({ json: {
  member_id: id,
  trigger_type: triggerData.trigger_type,
  trigger_context: triggerData.affected_class_names || '',
  send_surveys: true
} }));

// Same cooldown logic for studio-wide trigger
const triggerData = $('IF: Studio Threshold Breached?').first().json;
const logData = $('Load Survey Sent Log (Studio)').first().json;

const COOLDOWN_DAYS = 35;
const today = new Date();

const sentMap = {};
(logData.survey_sent_log || []).forEach(r => { sentMap[r.member_id] = new Date(r.last_survey_sent); });

const eligible = (triggerData.candidate_member_ids || []).filter(id => {
  const lastSent = sentMap[id];
  if (!lastSent) return true;
  const daysSince = (today - lastSent) / (1000 * 60 * 60 * 24);
  return daysSince >= COOLDOWN_DAYS;
});

if (eligible.length === 0) {
  return [{ json: { send_surveys: false, reason: 'All candidates in cooldown window.' } }];
}

return eligible.map(id => ({ json: {
  member_id: id,
  trigger_type: triggerData.trigger_type,
  drop_pct: triggerData.drop_pct,
  send_surveys: true
} }));

// Format the survey invitation email for each eligible member
// Survey link is a Tally.so form with member_id pre-filled as a hidden field
const member = $input.first().json;
const SURVEY_BASE_URL = 'https://tally.so/r/WOPxRR?member_id=M001';
const surveyUrl = `${SURVEY_BASE_URL}?member_id=${member.member_id}`;

const subject = 'A quick question about your sessions';
const body = `<p>Hi,</p>
<p>We noticed things have been a little quieter at the studio lately and we wanted to check in with you. It would really help us to hear how things have been going for you.</p>
<p>We have a few quick questions; it will take less than a minute:</p>
<p><a href="${surveyUrl}" style="background:#222;color:#fff;padding:10px 18px;text-decoration:none;border-radius:4px">Share your feedback</a></p>
<p>You can also just reply to this email if you prefer to write directly.</p>
<p>Thanks,<br>The team at YOUR GYM</p>
<p style="font-size:11px;color:#aaa">You can opt out of these check-in emails at any time by replying with 'unsubscribe'. Your response is voluntary and confidential.</p>`;

return [{ json: { member_id: member.member_id, trigger_type: member.trigger_type, email_subject: subject, email_body: body, survey_url: surveyUrl } }];

const member = $input.first().json;
const SURVEY_BASE_URL = 'https://tally.so/r/WOPxRR?member_id=M001';
const surveyUrl = `${SURVEY_BASE_URL}?member_id=${member.member_id}`;

const subject = 'A quick question about your sessions';
const body = `<p>Hi,</p>
<p>We noticed things have been a little quieter at the studio lately and we wanted to check in with you. 
It would really help us to hear how things have been going for you.</p>
<p>We have a few quick questions, it will take less than a minute:</p>
<p><a href="${surveyUrl}" style="background:#222;color:#fff;padding:10px 18px;text-decoration:none;border-radius:4px">Share your feedback</a></p>
<p>You can also just reply to this email if you prefer to write directly.</p>
<p>Thanks,<br>The team at YOUR GYM </p>
<p style="font-size:11px;color:#aaa">You can opt out of these check-in emails at any time by replying with 'unsubscribe'. Your response is voluntary and confidential.</p>`;

return [{ json: { member_id: member.member_id, trigger_type: member.trigger_type, email_subject: subject, email_body: body, survey_url: surveyUrl } }];

// Log that a survey was sent — prevents re-sending within cooldown window
const member = $input.first().json;
const today = new Date().toISOString().split('T')[0];

// In production: append this row to survey_sent_log.csv
// For demo: return the log entry that would be written
return [{ json: {
  log_entry: { member_id: member.member_id, last_survey_sent: today, trigger_type: member.trigger_type },
  status: 'Survey sent and logged.'
} }];

const member = $input.first().json;
const today = new Date().toISOString().split('T')[0];

return [{ json: {
  log_entry: { member_id: member.member_id, last_survey_sent: today, trigger_type: member.trigger_type },
  status: 'Survey sent and logged.'
} }];

// Parse Tally webhook payload and standardise to survey_responses.csv format
const payload = $input.first().json;

// Tally sends field responses as an array — map by label
const fields = payload.data?.fields || [];
const get = (label) => fields.find(f => f.label === label)?.value ?? null;

const member_id  = payload.data?.hiddenFields?.member_id || get('member_id') || 'UNKNOWN';
const satisfaction_score = parseInt(get('How satisfied are you with your sessions lately? (1-5)')) || null;
const nps_score      = parseInt(get('How likely are you to recommend us? (0-10)')) || null;
const feedback       = get('Is there anything getting in the way?') || '';
const goal_progress  = get('How is your progress towards your goal?') || null;

const today = new Date().toISOString().split('T')[0];

// In production: append to survey_responses.csv
return [{ json: {
  member_id,
  survey_date: today,
  satisfaction_score,
  nps_score,
  feedback,
  goal_progress,
  status: 'Response received and logged.'
} }];

const now = new Date();
const firstOfThisMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const monthLabel = now.toLocaleDateString('en-GB', { month: 'long', year: 'numeric' });

// Real + representative responses for March 2026
const allResponses = [
  // Real submission from Tally (Mar 31)
  { member_id: 'UNKNOWN', survey_date: '2026-03-31', satisfaction_score: null, nps_score: null, feedback: '', goal_progress: null },
  // Representative demo responses
  { member_id: 'M001', survey_date: '2026-03-24', satisfaction_score: 3, nps_score: 5, feedback: 'Been busy with work, hoping to get back on track soon.', goal_progress: 'falling_behind' },
  { member_id: 'M003', survey_date: '2026-03-25', satisfaction_score: 2, nps_score: 4, feedback: 'Classes are good but I feel like my progress has stalled.', goal_progress: 'falling_behind' },
  { member_id: 'M005', survey_date: '2026-03-21', satisfaction_score: 2, nps_score: 3, feedback: 'Feeling unmotivated, not sure the plan suits me anymore.', goal_progress: 'falling_behind' },
  { member_id: 'M007', survey_date: '2026-03-26', satisfaction_score: 4, nps_score: 7, feedback: 'Still finding my rhythm as a new member.', goal_progress: 'getting_started' },
  { member_id: 'M008', survey_date: '2026-03-23', satisfaction_score: 2, nps_score: 4, feedback: 'Schedule conflicts making it hard to come in regularly.', goal_progress: 'falling_behind' }
];

const filtered = allResponses.filter(r => {
  if (!r.survey_date) return true;
  return new Date(r.survey_date) >= firstOfThisMonth;
});

return filtered.map(r => ({ json: { ...r, month: monthLabel } }));

// Collect all input items as the responses array
const responses = $input.all().map(i => i.json);
const monthLabel = responses[0]?.month || 'March 2026';

if (responses.length === 0) {
  return [{ json: { email_html: `<p>No survey responses received in ${monthLabel}.</p>`, skip: true } }];
}

const scored = responses.filter(r => r.satisfaction_score !== null);
const avgSatisfaction = scored.length > 0
  ? (scored.reduce((s, r) => s + (r.satisfaction_score || 0), 0) / scored.length).toFixed(1)
  : 'N/A';
const avgNps = scored.length > 0
  ? (scored.reduce((s, r) => s + (r.nps_score || 0), 0) / scored.length).toFixed(1)
  : 'N/A';
const lowSatisfaction = responses.filter(r => r.satisfaction_score !== null && r.satisfaction_score <= 2);

const goalCounts = {};
responses.forEach(r => {
  const g = r.goal_progress || 'not_specified';
  goalCounts[g] = (goalCounts[g] || 0) + 1;
});

const feedbackRows = responses
  .filter(r => r.feedback && r.feedback.trim() !== '')
  .map(r => `<tr><td style="padding:8px;border-bottom:1px solid #eee;">${r.member_id}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.survey_date}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.satisfaction_score ?? 'N/A'}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.nps_score ?? 'N/A'}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.goal_progress || '-'}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.feedback}</td></tr>`)
  .join('');

const allRows = responses
  .map(r => `<tr><td style="padding:8px;border-bottom:1px solid #eee;">${r.member_id}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.survey_date}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.satisfaction_score ?? 'N/A'}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.nps_score ?? 'N/A'}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.goal_progress || '-'}</td><td style="padding:8px;border-bottom:1px solid #eee;">${r.feedback || '-'}</td></tr>`)
  .join('');

const goalBreakdown = Object.entries(goalCounts)
  .map(([k, v]) => `<li><strong>${k.replace(/_/g, ' ')}:</strong> ${v} member${v > 1 ? 's' : ''}</li>`)
  .join('');

const alertBlock = lowSatisfaction.length > 0
  ? `<div style="background:#fff3cd;border-left:4px solid #ffc107;padding:12px 16px;margin-bottom:20px;border-radius:4px;"><strong>⚠️ ${lowSatisfaction.length} member${lowSatisfaction.length > 1 ? 's' : ''} rated satisfaction ≤ 2</strong> — consider proactive outreach.<br>${lowSatisfaction.map(r => `<span style="margin-right:12px;">• ${r.member_id} (score: ${r.satisfaction_score})</span>`).join('')}</div>`
  : `<div style="background:#d4edda;border-left:4px solid #28a745;padding:12px 16px;margin-bottom:20px;border-radius:4px;">✅ No critical satisfaction alerts this month.</div>`;

const html = `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px;color:#333;">

  <div style="background:#1a1a2e;padding:24px 28px;border-radius:8px 8px 0 0;">
    <h1 style="color:#fff;margin:0;font-size:22px;">📊 Spottr — Monthly Survey Summary</h1>
    <p style="color:#aaa;margin:6px 0 0;">${monthLabel}</p>
  </div>

  <div style="background:#f8f9fa;padding:20px 28px;">

    <div style="display:flex;gap:16px;margin-bottom:24px;flex-wrap:wrap;">
      <div style="flex:1;min-width:140px;background:#fff;border-radius:8px;padding:16px;text-align:center;box-shadow:0 1px 4px rgba(0,0,0,0.08);">
        <div style="font-size:32px;font-weight:bold;color:#1a1a2e;">${responses.length}</div>
        <div style="color:#666;font-size:13px;margin-top:4px;">Responses</div>
      </div>
      <div style="flex:1;min-width:140px;background:#fff;border-radius:8px;padding:16px;text-align:center;box-shadow:0 1px 4px rgba(0,0,0,0.08);">
        <div style="font-size:32px;font-weight:bold;color:#1a1a2e;">${avgSatisfaction}</div>
        <div style="color:#666;font-size:13px;margin-top:4px;">Avg Satisfaction (1–5)</div>
      </div>
      <div style="flex:1;min-width:140px;background:#fff;border-radius:8px;padding:16px;text-align:center;box-shadow:0 1px 4px rgba(0,0,0,0.08);">
        <div style="font-size:32px;font-weight:bold;color:#1a1a2e;">${avgNps}</div>
        <div style="color:#666;font-size:13px;margin-top:4px;">Avg NPS (0–10)</div>
      </div>
      <div style="flex:1;min-width:140px;background:#fff;border-radius:8px;padding:16px;text-align:center;box-shadow:0 1px 4px rgba(0,0,0,0.08);">
        <div style="font-size:32px;font-weight:bold;color:#e74c3c;">${lowSatisfaction.length}</div>
        <div style="color:#666;font-size:13px;margin-top:4px;">Low Satisfaction Alerts</div>
      </div>
    </div>

    ${alertBlock}

    <h2 style="font-size:16px;border-bottom:2px solid #1a1a2e;padding-bottom:6px;">📋 All Responses</h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px;margin-bottom:24px;">
      <thead><tr style="background:#1a1a2e;color:#fff;">
        <th style="padding:10px 8px;text-align:left;">Member</th>
        <th style="padding:10px 8px;text-align:left;">Date</th>
        <th style="padding:10px 8px;text-align:left;">Satisfaction</th>
        <th style="padding:10px 8px;text-align:left;">NPS</th>
        <th style="padding:10px 8px;text-align:left;">Goal Progress</th>
        <th style="padding:10px 8px;text-align:left;">Feedback</th>
      </tr></thead>
      <tbody>${allRows}</tbody>
    </table>

    <h2 style="font-size:16px;border-bottom:2px solid #1a1a2e;padding-bottom:6px;">🎯 Goal Progress Breakdown</h2>
    <ul style="margin:0 0 24px;padding-left:20px;">${goalBreakdown}</ul>

    <p style="font-size:12px;color:#999;border-top:1px solid #ddd;padding-top:12px;">Generated by Spottr Automation · ${new Date().toLocaleDateString('en-GB', {day:'numeric',month:'long',year:'numeric'})}</p>
  </div>

</body>
</html>`;

return [{ json: { email_html: html, response_count: responses.length, month: monthLabel, skip: false } }];
